deploy:
  stage: deploy
  image: alpine
  script:
    - apk add --no-cache openssh-client
    - mkdir -p ~/.ssh
    - echo "$SSH_PRIVATE_KEY" > ~/.ssh/id_rsa
    - chmod 600 ~/.ssh/id_rsa
    - ssh-keyscan $SERVER_IP >> ~/.ssh/known_hosts
    - chmod 644 ~/.ssh/known_hosts
    - scp -r .env docker-compose.yml $SSH_USER@$SERVER_IP:/home/$SSH_USER/app
    - ssh $SSH_USER@$SERVER_IP "cd /home/$SSH_USER/app && docker-compose down && docker-compose pull && docker-compose up -d"
  only:
    - main


